    /**
     * Returns a string representation of the specified object.
     *
     * <p>Note: arrays are rendered by content, and a {@code Collection} argument is rendered element-wise
     * (e.g., {@code "[a, b]"}). Any other object - including a bare {@code Iterable} or {@code Iterator}
     * that is not a {@code Collection} - is rendered via its own {@code toString()} and is <i>not</i>
     * iterated/consumed.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * N.toString(1);               // returns "1"
     * N.toString((Object) null);   // returns "null"
     * }</pre>
     *
     * @param obj the object to be represented as a string, may be {@code null}
     * @return the String representation of the object. If the object is {@code null}, the string {@code "null"} is returned.
     */
    public static String toString(final Object obj) {
        if (obj == null) {
            return Strings.NULL;
        } else if (obj instanceof CharSequence) {
            return obj.toString();
        }

        if (obj.getClass().isArray()) {
            return typeOf(obj.getClass()).toString(obj);
        }

        // NOTE: Iterator/Iterable are intentionally NOT rendered element-wise here. Doing so would
        //    (a) EXHAUST an Iterator argument as a side effect - problematic because this method also
        //    stringifies arguments for the checkArgument/checkState/format(...) message pipeline - and
        //    (b) override any meaningful custom toString() defined by an Iterable. Only Collection is
        //    rendered element-wise (below); a bare Iterable/Iterator falls through to obj.toString().
        //
        //    if (obj instanceof final Iterator<?> iter) { // NOSONAR
        //        return Strings.join(iter, ", ", "[", "]");
        //    }
        //    if (obj instanceof final Iterable<?> iter) { // NOSONAR
        //        return Strings.join(iter, ", ", "[", "]");
        //    }

        if (obj instanceof final Collection<?> c) { // NOSONAR
            return Strings.join(c, ", ", "[", "]");
        }

        final Integer typeIdx = CLASS_TYPE_ENUM.get(obj.getClass());

        if (typeIdx == null) {
            return obj.toString();
        }

        switch (typeIdx) {
            case 21:
                return toString(((Boolean) obj).booleanValue());

            case 22:
                return toString(((Character) obj).charValue());

            case 23:
                return toString(((Byte) obj).byteValue());

            case 24:
                return toString(((Short) obj).shortValue());

            case 25:
                return toString(((Integer) obj).intValue());

            case 26:
                return toString(((Long) obj).longValue());

            //    case 27:
            //        return toString(((Float) obj).floatValue());
            //
            //    case 28:
            //        return toString(((Double) obj).doubleValue());

            default:
                return obj.toString();
        }
    }

