    /**
     * Checks if any of the specified objects is {@code null}.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * N.anyNull("a", "b");    // returns false
     * N.anyNull("a", null);   // returns true
     * }</pre>
     *
     * @param a the first object to check
     * @param b the second object to check
     * @return {@code true} if any of the objects is {@code null}, otherwise {@code false}
     */
    public static boolean anyNull(final Object a, final Object b) {
        return a == null || b == null;
    }

    /**
     * Checks if any of the specified objects is {@code null}.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * N.anyNull("a", "b", "c");    // returns false
     * N.anyNull("a", null, "c");   // returns true
     * }</pre>
     *
     * @param a the first object to check
     * @param b the second object to check
     * @param c the third object to check
     * @return {@code true} if any of the objects is {@code null}, otherwise {@code false}
     */
    public static boolean anyNull(final Object a, final Object b, final Object c) {
        return a == null || b == null || c == null;
    }

    /**
     * Checks if any element in the specified array is {@code null}.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * N.anyNull("a", null);         // returns true
     * N.anyNull("a", "b");          // returns false
     * N.anyNull((Object[]) null);   // returns false (null/empty array)
     * }</pre>
     *
     * @param a the array of objects to check
     * @return {@code true} if any element in the specified array is {@code null}, otherwise {@code false}
     */
    public static boolean anyNull(final Object... a) {
        if (isEmpty(a)) {
            return false;
        }

        for (final Object e : a) {
            if (e == null) {
                return true;
            }
        }

        return false;
    }

    /**
     * Checks if any element in the specified iterable is {@code null}.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * N.anyNull(Arrays.asList("a", null));   // returns true
     * N.anyNull(Arrays.asList("a", "b"));    // returns false
     * N.anyNull(Collections.emptyList());    // returns false
     * }</pre>
     *
     * @param c the iterable of objects to check
     * @return {@code true} if any element in the specified iterable is {@code null}, otherwise {@code false}
     */
    public static boolean anyNull(final Iterable<?> c) {
        if (c == null) {
            return false;
        }

        for (final Object e : c) {
            if (e == null) {
                return true;
            }
        }

        return false;
    }

