    public static <K, V> IdentityHashMap<K, V> newIdentityHashMap() { //NOSONAR
        return new IdentityHashMap<>();
    }

    /**
     * Creates a new instance of an IdentityHashMap sized to hold the specified expected number of entries.
     *
     * <p>Note: the argument is treated as the <i>expected entry count</i>, not the raw initial capacity:
     * it is scaled up internally (approximately {@code expectedSize / 0.75 + 1}) before being passed to the
     * {@code IdentityHashMap(int expectedMaxSize)} constructor (which applies its own sizing on top).
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * N.newIdentityHashMap(8); // returns empty IdentityHashMap
     * N.newIdentityHashMap(0); // returns empty IdentityHashMap
     * }</pre>
     *
     * @param <K> the type of keys maintained by this map
     * @param <V> the type of mapped values
     * @param expectedSize the expected number of entries to be added to the map
     * @return a new instance of an IdentityHashMap sized for the specified expected number of entries
     */
    public static <K, V> IdentityHashMap<K, V> newIdentityHashMap(final int expectedSize) { //NOSONAR
        return new IdentityHashMap<>(initHashCapacity(expectedSize));
    }

    /**
     * Creates a new instance of an IdentityHashMap with the entries from the specified map.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * N.newIdentityHashMap(N.asMap("a", 1)); // returns IdentityHashMap with one entry
     * N.newIdentityHashMap(null);            // returns empty IdentityHashMap
     * }</pre>
     *
     * @param <K> the type of keys maintained by this map
     * @param <V> the type of mapped values
     * @param m the map whose elements are to be placed into this map
     * @return a new instance of an IdentityHashMap containing the entries from the specified map
     */
    public static <K, V> IdentityHashMap<K, V> newIdentityHashMap(final Map<? extends K, ? extends V> m) { //NOSONAR
        return isEmpty(m) ? new IdentityHashMap<>() : new IdentityHashMap<>(m);
    }

